from prefect import flow, task

@task
def fetch_data(url: str) -> dict:
    import httpx
    response = httpx.get(url)
    response.raise_for_status()
    return response.json()

@task
def transform_data(data: dict) -> list:
    return [item for item in data["results"] if item["active"]]

@task
def save_data(records: list, path: str) -> None:
    import json
    with open(path, "w") as f:
        json.dump(records, f)

@flow(name="etl-pipeline")
def etl_pipeline(url: str, output_path: str) -> None:
    raw = fetch_data(url)
    cleaned = transform_data(raw)
    save_data(cleaned, output_path)

