from prefect import flow, task
from prefect.task_runners import ConcurrentTaskRunner

@task
def process_chunk(chunk_id: int) -> str:
    import time
    time.sleep(2)
    return f"chunk-{chunk_id}-done"

@flow(task_runner=ConcurrentTaskRunner())
def parallel_pipeline(num_chunks: int = 5) -> list:
    # .submit() is required for concurrent execution
    futures = [process_chunk.submit(i) for i in range(num_chunks)]
    # .result() blocks until complete
    return [f.result() for f in futures]

